import pytest
import asyncio
from mymodule import MeshRouter, research_agent, writer_agent, reviewer_agent

@pytest.fixture
def mesh():
    return MeshRouter(
        agents={
            "research": research_agent,
            "writer": writer_agent,
            "reviewer": reviewer_agent,
        },
        adjacency={
            "research": {"writer"},
            "writer":   {"reviewer"},
            "reviewer": set(),
        },
    )

@pytest.mark.asyncio
async def test_authorized_call_succeeds(mesh):
    """research → writer is wired; must not raise."""
    # Mock writer to avoid real LLM call
    async def mock_writer(payload, client): return "draft"
    mesh.agents["writer"] = mock_writer
    result = await mesh.call("research", "writer", "some chunks", client=None)
    assert result == "draft"

@pytest.mark.asyncio
async def test_unauthorized_call_raises(mesh):
    """research → reviewer is NOT wired; must raise PermissionError."""
    with pytest.raises(PermissionError, match="not wired"):
        await mesh.call("research", "reviewer", "chunks", client=None)

@pytest.mark.asyncio
async def test_reviewer_is_sink(mesh):
    """reviewer has no outbound connections; any call from it must fail."""
    with pytest.raises(PermissionError):
        await mesh.call("reviewer", "writer", "feedback", client=None)

def test_adjacency_map_is_complete(mesh):
    """Every agent in the adjacency map must exist in the agents dict."""
    for caller, callees in mesh.adjacency.items():
        assert caller in mesh.agents, f"Caller {caller!r} not in agents"
        for callee in callees:
            assert callee in mesh.agents, f"Callee {callee!r} not in agents"

def detect_cycles(adjacency: dict[str, set[str]]) -> list[list[str]]:
    """Return all cycles found in the adjacency map using DFS."""
    cycles: list[list[str]] = []
    visited: set[str] = set()
    path: list[str] = []

    def dfs(node: str) -> None:
        if node in path:
            cycle_start = path.index(node)
            cycles.append(path[cycle_start:] + [node])
            return
        if node in visited:
            return
        visited.add(node)
        path.append(node)
        for neighbor in adjacency.get(node, set()):
            dfs(neighbor)
        path.pop()

    for node in adjacency:
        dfs(node)

    return cycles

# Run at system startup — fail fast if cycles exist
def validate_mesh(adjacency: dict[str, set[str]]) -> None:
    cycles = detect_cycles(adjacency)
    if cycles:
        formatted = [" → ".join(c) for c in cycles]
        raise ValueError(
            f"Mesh adjacency map contains cycles:\n" +
            "\n".join(f"  {c}" for c in formatted)
        )

# Example:
safe_adjacency = {
    "research": {"writer"},
    "writer":   {"reviewer"},
    "reviewer": set(),
}
validate_mesh(safe_adjacency)   # passes

cyclic_adjacency = {
    "A": {"B"},
    "B": {"C"},
    "C": {"A"},   # cycle!
}
